import * as React from 'react';
import { useContext } from 'react';
import { Icon, TooltipHost, TooltipDelay } from '@fluentui/react';
import { AppContext } from '../context/AppContext';
import { AppView } from '../models/ITimesheetModels';
import DashboardAnalytics from '../components/DashboardAnalytics';
import './HomePage.module.scss';

interface INavCard {
  view: AppView;
  iconName: string;
  value: string;
  label: string;
  subtitle: string;
  color: string;
  roles: ('Employee' | 'Manager' | 'Admin')[];
}

const NAV_CARDS: INavCard[] = [
  {
    view: 'DailyForm',
    iconName: 'CalendarDay',
    value: "Today",
    label: "My Timesheet",
    subtitle: "Enter today's hours",
    color: '#0078d4',
    roles: ['Employee', 'Manager', 'Admin'],
  },
  {
    view: 'MyHistory',
    iconName: 'History',
    value: "History",
    label: "My Submissions",
    subtitle: "Past timesheets",
    color: '#107c41',
    roles: ['Employee', 'Manager', 'Admin'],
  },
  {
    view: 'ManagerDashboard',
    iconName: 'People',
    value: "Team",
    label: "Team Timesheets",
    subtitle: "Review & approve",
    color: '#e8a600',
    roles: ['Manager', 'Admin'],
  },
  {
    view: 'ExportPanel',
    iconName: 'ExcelDocument',
    value: "Export",
    label: "Export Report",
    subtitle: "Excel or PDF",
    color: '#107c41',
    roles: ['Manager', 'Admin'],
  },
  {
    view: 'AdminPanel',
    iconName: 'Settings',
    value: "Admin",
    label: "Manage Projects",
    subtitle: "Projects & categories",
    color: '#c4314b',
    roles: ['Manager', 'Admin'],
  },
];

const HomePage: React.FC = () => {
  const { currentUser, navigateTo } = useContext(AppContext);

  const visibleCards = NAV_CARDS.filter(
    (c) => c.roles.indexOf(currentUser.role) !== -1
  );

  return (
    <div className="webpart-container" style={{border: '1px solid #d5d5d5', padding: '20px', borderRadius: '20px', backgroundColor: '#f3f4f4'}}>
      <div className="dashboard-root">

        {/* Header */}
        <div className="dashboard-header">
          <div className="header-content">
            <h1 className="dashboard-page-title">TimeSheet Dashboard</h1>
            <p className="dashboard-section-title">
              Welcome, <strong>{currentUser.displayName}</strong> · {currentUser.role}
            </p>
          </div>
        </div>

        {/* Top Navigation Bar */}
        <div className="pivot-navigation" role="navigation" aria-label="Main navigation">
          <div className="pivot-container">
            <div className="pivot-links">
              {visibleCards.map((card, index) => (
                <TooltipHost
                  key={card.view}
                  content={`${card.subtitle} - Click to navigate`}
                  delay={TooltipDelay.medium}
                >
                  <button
                    className={`pivot-link ${index === 0 ? 'pivot-link-active' : ''}`}
                    onClick={() => navigateTo(card.view)}
                    aria-label={`${card.label} - ${card.subtitle}`}
                    data-testid={`nav-${card.view}`}
                  >
                    <div className="pivot-link-content">
                      <Icon
                        iconName={card.iconName}
                        className="pivot-icon"
                        styles={{ 
                          root: { 
                            fontSize: 16, 
                            color: card.color,
                            marginRight: 8
                          } 
                        }}
                      />
                      <span className="pivot-text">{card.label}</span>
                    </div>
                    <div 
                      className="pivot-underline" 
                      style={{ 
                        backgroundColor: card.color,
                        opacity: index === 0 ? 1 : 0
                      }} 
                    />
                  </button>
                </TooltipHost>
              ))}
            </div>
            <div className="pivot-border" />
          </div>
        </div>

        {/* Dashboard Analytics Section */}
        <DashboardAnalytics />

      </div>
    </div>
  );
};

export default HomePage;
